class Solution:
    def letterCombinations(self, digits):
        if not digits:
            return []
        mapping = {'2': 'abc', '3': 'def', '4': 'ghi', '5': 'jkl', '6': 'mno', '7': 'pqrs', '8': 'tuv', '9': 'wxyz'}
        out = []
        def dfs(index, path):
            if index == len(digits):
                out.append(path)
                return
            for ch in mapping[digits[index]]:
                dfs(index + 1, path + ch)
        dfs(0, '')
        return out
